void run_can_simulation(void)
{
    // Use the actual FreeRTOS tick count or a hardware timer for precision
    uint32_t current_time = xTaskGetTickCount() * portTICK_PERIOD_MS;
    static uint32_t last_sent_time[102] = {0}; // Tracks the last time each message was sent
    static uint8_t sample_index[102] = {0};    // Tracks which history sample we are on
    CanIf_MsgType msg;

    for (int i = 0; i < sizeof(can_tx_message)/sizeof(can_tx_message[0]); i++)
    {
        uint32_t target_interval;

        // Determine the interval: use the difference between log samples
        // or a fixed cycle time from the DBC.
        if (can_tx_message[i].sample_count > 1) {
            target_interval = can_tx_message[i].history.sending_timestmp_ms[1] -
                             can_tx_message[i].history.sending_timestmp_ms[0];
        } else {
            target_interval = 1000; // Default fallback 1s
        }

        // Check if it's time to send this specific message ID again
        if ((current_time - last_sent_time[i]) >= target_interval)
        {
            uint8_t s = sample_index[i];

            msg.id = can_tx_message[i].can_id;
            msg.dlc = 8;
            memcpy(msg.data, can_tx_message[i].history.pay_load[s], 8);
            msg.is_extended = true;

            if (CanIf_Transmit(&msg) == BMU_OK)
            {
                last_sent_time[i] = current_time;

                // Advance to next data sample in the history for this ID
                sample_index[i] = (sample_index[i] + 1) % can_tx_message[i].sample_count;
            }
        }
    }
}
